query PostDetail($id: ID!, $repliesAfter: String) {
    node(id: $id) {
        ... on Post {
            ...PostFields
            visibility
            replyTarget {
                ...PostFields
            }
            sharedPost {
                ...SharedPostFields
            }
            reactionGroups {
                __typename
                ... on EmojiReactionGroup {
                    emoji
                    reactors(first: 20) {
                        edges {
                            node {
                                ...ActorFields
                            }
                        }
                        totalCount
                        viewerHasReacted
                    }
                }
                ... on CustomEmojiReactionGroup {
                    customEmoji {
                        id
                        name
                        imageUrl
                    }
                    reactors(first: 20) {
                        edges {
                            node {
                                ...ActorFields
                            }
                        }
                        totalCount
                        viewerHasReacted
                    }
                }
            }
            replies(first: 20, after: $repliesAfter) {
                edges {
                    cursor
                    node {
                        ...PostFields
                        sharedPost {
                            ...SharedPostFields
                        }
                    }
                }
                pageInfo {
                    hasNextPage
                    endCursor
                }
            }
        }
    }
}

