                    if (ctx != null) {
                        val nestingLevel = (listStack.size - 1).coerceAtLeast(0)
                        val marker = if (ctx.ordered) {
                            ctx.itemIndex++
                            "${ctx.itemIndex}."
                        } else {
                            "\u2022"
                        }
                        val baseIndent = nestingLevel * 1.2f
                        val markerIndent = if (ctx.ordered) {
                            0.95f + (marker.length * 0.33f)
