                    }
                }

                // Ruby annotations
                "ruby" -> {
                    // No special action needed for opening <ruby>
                }
                "rt" -> {
                    insideRt = true
                    pushStyle(SpanStyle(
                        fontSize = 0.6.em,
                        baselineShift = BaselineShift.Superscript
                    ))
                }
                "rp" -> {
                    insideRp = true
                }

                // Invisible spans
                "span" -> {
                    val classes = attrs["class"] ?: ""
                    if ("invisible" in classes) {
                        insideInvisibleSpan = true
                        invisibleSpanDepth++
                    }
                }
            }
        } else {
            // Closing tags
            when (tagName) {
                "h1", "h2", "h3", "h4", "h5", "h6" -> {
                    if (headingLevel > 0) {
                        pop()
                        headingLevel = 0
                    }
                }

                "pre" -> {
                    if (preDepth > 0) {
                        preDepth--
                        pop()
                    }
                }

                "code" -> {
                    if (codeDepth > 0) {
                        codeDepth--
                        if (preDepth == 0) {
                            // Only pop if we pushed for inline code
                            pop()
                        }
                    }
                }

