fun `splitIntoBlocks extracts headings when splitHeadings is true`() {
    val html = "<p>intro</p><h2 id=\"sec\">Section</h2><p>body</p>"
    val blocks = splitIntoBlocks(html, splitHeadings = true)
    assertEquals(3, blocks.size)
