        modifier = Modifier
            .fillMaxWidth()
            .clickable { onClick(item.id) }
            .padding(start = indent, top = 6.dp, bottom = 6.dp),
    )

    item.children.forEach { child ->
        TocEntry(item = child, baseLevel = baseLevel, onClick = onClick)
    }
}
